export const NEWS_TRENDING_URL = 'https://bing-news-search1.p.rapidapi.com/news/trendingtopics?safeSearch=Off&textFormat=Raw&count=4';

export const setUrlCategory = category => `https://bing-news-search1.p.rapidapi.com/news?textFormat=Raw&safeSearch=Off&category=${category}&count=10`;

export const setUrlArticle = title => `https://newscatcher.p.rapidapi.com/v1/search?q=${title}&lang=en&sort_by=relevancy&search_in=title&page=1&media=True`;

export const setUrlSearch = text => `https://bing-news-search1.p.rapidapi.com/news/search?q=${text}&safeSearch=Off&textFormat=Raw&freshness=Day&count=1`;

export const optionsNews = {
  method: 'GET',
  headers: {
    'x-bingapis-sdk': 'true',
    'x-rapidapi-key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
    'x-rapidapi-host': 'bing-news-search1.p.rapidapi.com',
  },
};

export const optionsArticles = {
  method: 'GET',
  headers: {
    'x-rapidapi-key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
    'x-rapidapi-host': 'newscatcher.p.rapidapi.com',
  },
};

export const request = (url, option) => (
  fetch(url, option)
    .then(response => response.json())
    .then(res => res)
);

export const getAllNews = async() => {
  const result = await request(NEWS_TRENDING_URL.slice(0, -9), optionsNews);

  return result.value;
};
