export const getCategoryNews = async(q) => {
  const result = await request(setUrlCategory(q), optionsNews);

  return result.value;
};

export const getSearchNews = async(q) => {
  const result = await request(setUrlSearch(q), optionsNews);

  return result;
};

export const getArticlesNews = async(q) => {
  const result = await request(setUrlArticle(q), optionsArticles);

  return result.articles.filter(res => res.author !== null);
};
